package sem

import (
	"context"
	"os"
	"path/filepath"
	"strings"
	"testing"
)

func TestTrail7ReviewUnsupportedRenameStillWarns(t *testing.T) {
	repo := t.TempDir()
	git(t, repo, "init")
	git(t, repo, "config", "user.name", "Entire Graph Test")
	git(t, repo, "config", "user.email", "graph@example.com")
	write(t, repo, "sample.go", "package sample\n\nfunc Run() {}\n")
	git(t, repo, "add", ".")
	git(t, repo, "commit", "-m", "initial")
	base := rev(t, repo, "HEAD")
	if err := os.Rename(filepath.Join(repo, "sample.go"), filepath.Join(repo, "sample.ps1")); err != nil {
		t.Fatal(err)
	}
	git(t, repo, "add", "-A")
	git(t, repo, "commit", "-m", "rename across parser boundary")
	head := rev(t, repo, "HEAD")

	result, err := AnalyzeGitRange(context.Background(), repo, base, head, nil)
	if err != nil {
		t.Fatal(err)
	}
	for _, warning := range result.Warnings {
		if warning.Code == "W_UNSUPPORTED_FILE" {
			return
		}
	}
	t.Fatalf("rename crossed into an unsupported file but no warning was emitted; result=%#v", result)
}

func TestTrail7ReviewShebangScriptRemainsSemanticallyAnalyzed(t *testing.T) {
	repo := t.TempDir()
	git(t, repo, "init")
	git(t, repo, "config", "user.name", "Entire Graph Test")
	git(t, repo, "config", "user.email", "graph@example.com")
	write(t, repo, "bin/tool", "#!/usr/bin/env python3\n\ndef run(value):\n    return value\n")
	git(t, repo, "add", ".")
