	snapshot, err := BuildProviderSnapshot(t.Context(), repo, "test-version")
	if err != nil {
		t.Fatal(err)
	}

	var whichShim []RelationRecord
	for _, r := range snapshot.Relations {
		if r.Type != "USES_TYPE" && r.Type != "PARAM_TYPE" && r.Type != "RETURNS_TYPE" {
			continue
